@app.route("/graphql", methods=["POST"])
def graphql_server():
    data = request.get_json()
    
    query_string = data.get("query", "")
    
    if len(query_string) > 10000:
        return jsonify({"errors": [{"message": "Query too large"}]}), 400
    
    if not validate_query_complexity(query_string):
        return jsonify({"errors": [{"message": "Query too complex"}]}), 400
    
    query_cost = calculate_query_cost(query_string)
    if query_cost > QUERY_COST_LIMIT:
        return jsonify({"errors": [{"message": "Query cost exceeds limit"}]}), 400
    
    if query_string.count("{") > 20:
        return jsonify({"errors": [{"message": "Query nesting too deep"}]}), 400
    
    success, result = graphql_sync(
        schema,
        data,
        context_value={"request": request},
        middleware=[auth_middleware],
        debug=app.debug
    )
    
    status_code = 200 if success else 400
    return jsonify(result), status_code

